oup_id\": 4, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Đăng nhập\", \"display_order\": 1, \"detail_description\": \"Chức năng cho phép người dùng sử dụng được cấp tài khoản trên hệ thống đăng nhập vào hệ thống để thực hiện các nghiệp vụ theo phạm vi được phân công theo phân quyền tài khoản. Chức năng Bệnh án gồm các tính năng:\\n- Nhập thông tin tài khoản \\n- Nhập thông tin kiểm tra hoặc OTP\\n- Lưu mật khẩu khi đăng nhập\\n- Đăng nhập vào hệ thống\"}, {\"id\": 78, \"uuid\": \"8ad3aef8-cde9-4245-a695-dd7b72e97fbc\", \"status\": \"ACTIVE\", \"group_id\": 4, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Trang chủ\", \"display_order\": 2, \"detail_description\": \"Chức năng cho phép người dùng truy cập vào trang chủ của bệnh viện để kiểm tra các thông báo được bộ phận chức năng nhập thông tin thông báo trên hệ thống. Chức năng Bệnh án gồm các tính năng:\\n- Hiển thị thông tin trang chủ của hệ thống\\n- Kiểm tra các thông tin thông báo trên trang chủ\"}, {\"id\": 79, \"uuid\": \"1648279b-d87c-4a4e-a219-138738738637\", \"status\": \"ACTIVE\", \"group_id\": 4, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Đăng xuất\", \"display_order\": 3, \"detail_description\": \"Chức năng cho phép người sử dụng thoát khỏi hệ thống khi đã đăng nhập trước ấy. Chức năng Bệnh án gồm các tính năng:\\n- Đăng xuất khỏi hệ thống quản lý bệnh viện\"}, {\"id\": 80, \"uuid\": \"e3bf28c0-4a1c-40bf-b2b7-6552d5c3647a\", \"status\": \"ACTIVE\", \"group_id\": 4, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Cấu hình các quyền truy cập HSBA\", \"display_order\": 4, \"detail_description\": \"Chức năng cho phép người cấu hình truy cập hồ sơ Bệnh án, kiểm soát truy cập của người dùng gồm xác thực người dùng, phân quyền người dùng theo từng vai trò công việc, thiết lập khoảng thời gian giới hạn cho phép người dùng truy cập vào phần mềm Chức năng Bệnh án gồm các tính năng:\\n- Hiển thị danh sách các quyền truy cập HSBệnh án\\n- Cấu hình truy cập HSBệnh án\"}, {\"id\": 81, \"uuid\": \"1914537a-9e93-4e03-b55c-4afad5f8e4b2\", \"status\": \"ACTIVE\", \"group_id\": 4, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Cấp quyền cho người dùng truy cập HSBA\", \"display_order\": 5, \"detail_description\": \"Chức năng cho phép người cấp quyền truy cập hồ sơ Bệnh án. Chức năng Bệnh án gồm các tính năng:\\n- Hiển thị danh sách hồ sơ Bệnh án\\n- Cập quyền truy cập HSBệnh án cho người dùng\"}, {\"id\": 82, \"uuid\": \"be9960bf-4cb7-4015-aea6-7cb511ed2f8b\", \"status\": \"ACTIVE\", \"group_id\": 4, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Quản lý log người dùng truy cập HSBA\", \"display_order\": 6, \"detail_description\": \"Chức năng cho phép người dùng truy cập, xem lại log các thao tác với hệ thống. Chức năng Bệnh án gồm các tính năng:\\n- Hiển thị log truy cập\\n- Xem chi tiết log truy cập của người dùng\"}], \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"group_name\": \"Quản trị hệ thống\", \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"display_order\": 1}, {\"id\": 5, \"uuid\": \"49ae51f2-76f1-453c-822a-9aab87badec6\", \"notes\": null, \"features\": [{\"id\": 83, \"uuid\": \"35ecc1c3-f7e6-45e7-87b5-1f91ea2afd6f\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:09\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:09\", \"updated_by\": 9, \"feature_name\": \"Quản lý HSBA mở\", \"display_order\": 1, \"detail_description\": \"Chức năng quản lý hồ sơ Bệnh án mở cho phép giải pháp EMR tiếp nhận dữ liệu khám chữa bệnh (Bệnh án gồm các phiếu, biểu mẫu, báo cáo…) theo định dạng XML từ hệ thống HIS. Chức năng Bệnh án gồm các tính năng :\\n- Tiếp nhận HSBệnh án từ HIS theo định dạng XML \\n- Hiển thị danh sách hồ sơ Bệnh án của bệnh nhân tiếp nhận từ HIS\\n- Hiển thị phiếu, Bệnh án có ký số theo định dạng PDF\\n- Ký số phiếu, biểu mẫu, báo cáo trong hồ sơ Bệnh án\\n- Lưu trữ hiển thị theo HL7\"}, {\"id\": 84, \"uuid\": \"5e15c0f6-90d2-49ed-b1c6-92c009d71f3e\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Đóng Bệnh án chuyển lưu trữ\", \"display_order\": 2, \"detail_description\": \"Chức năng quản lý hồ sơ Bệnh án mở cho phép giải pháp EMR tiếp nhận dữ liệu khám chữa bệnh (Bệnh án gồm các phiếu, biểu mẫu, báo cáo…) theo định dạng XML từ hệ thống HIS. Chức năng Bệnh án gồm các tính năng :\\n- Tiếp nhận HSBệnh án từ HIS theo định dạng XML \\n- Hiển thị danh sách hồ sơ Bệnh án của bệnh nhân tiếp nhận từ HIS\\n- Hiển thị phiếu, Bệnh án có ký số theo định dạng PDF\\n- Ký số phiếu, biểu mẫu, báo cáo trong hồ sơ Bệnh án\\n- Lưu trữ hiển thị theo HL7\"}, {\"id\": 85, \"uuid\": \"f5b3e52c-aafe-4b4f-a78e-45a7f116d979\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Tích hợp ký số dữ liệu Bệnh án\", \"display_order\": 3, \"detail_description\": \"Chức năng cho phép người dùng thực hiện ký số phiếu, HSBệnh án . Chức năng Bệnh án gồm các tính năng :\\n- Tìm kiếm file cần ký\\n- Ký số file XML\\n- Lưu trữ file XML\\n- Hiển thị phiếu đã ký\\n- Hủy ký số\"}, {\"id\": 86, \"uuid\": \"8ff41a8a-8aa2-4bdc-88df-578c05eb184b\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Tổng hợp danh sách lưu trữ HSBA\", \"display_order\": 4, \"detail_description\": \"Chức năng cho phép người dùng (bác sĩ, điều dưỡng) thực hiện lựa chọn tổng hợp các Bệnh án đã được phân loại thành một danh sách. Danh sách Bệnh án này sẽ được gửi về bộ phận Kế hoạch tổng hợp của cơ sở khám chữa bệnh để lưu trữ. Chức năng Bệnh án gồm các tính năng sau:\\n- Phân loại hồ sơ Bệnh án \\n- Cấp số lưu trữ\\n- Liệt kê/Tìm kiếm: Liệt kê theo ngày, mã phiếu, tên \\ndịch vụ\"}, {\"id\": 87, \"uuid\": \"9a85f430-27b3-464f-8302-f7e151f89b51\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Bàn giao HSBA\", \"display_order\": 5, \"detail_description\": \"Chức năng cho phép người dùng xem Tìm kiếm danh sách HSBệnh án, bàn giao cho phòng tổng hợp lưu trữ. Chức năng Bệnh án gồm các tính năng sau:\\n- Liệt kê/Tìm kiếm: Liệt kê theo ngày, mã phiếu, tên dịch vụ \\n- Xem danh sách HSBệnh án\\n- Xem chi tiết HSBệnh án\\n- Cập nhật trạng thái phiếu, Bệnh án\"}, {\"id\": 88, \"uuid\": \"416f65b4-cd0c-4024-adb0-a436261be928\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Duyệt nhận HSBA\", \"display_order\": 6, \"detail_description\": \"Chức năng cho phép người dùng duyệt nhận HSBệnh án chuyển lưu trữ. Chức năng Bệnh án gồm các tính năng chính sau:\\n- Cập nhật vị trí lưu trữ HSBệnh án\\n- Từ chối lưu trữ HSBệnh án\\n- Duyệt phiếu lưu trũ HSBệnh án\\n- In danh sách báo cáo bàn giao HSBệnh án\\n- Hiển thị, tìm kiếm phiếu tổng hợp bàn giao HSBệnh án trên lưới\"}, {\"id\": 89, \"uuid\": \"4ccf10e6-a154-4c6f-8986-d52ca37acce3\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Ký chốt hồ sơ Bệnh án\", \"display_order\": 7, \"detail_description\": \"Chức năng cho phép người dùng thực hiện ký số để chốt hồ sơ Bệnh án khi chuyển vào lưu trữ\\n- Xem danh sách hồ sơ Bệnh án\\n- Thực hiện ký số để chốt hồ sơ Bệnh án\"}, {\"id\": 90, \"uuid\": \"03aeba0b-730f-4db0-a6b7-e3f2d716720a\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Tra cứu lịch sử ký chốt HSBA\", \"display_order\": 8, \"detail_description\": \"Chức năng cho phép người dùng thực hiện tra cứu lịch sử ký chốt HSBệnh án\\n- Xem lịch sử ký chốt\\n- Ký lại đối với các phiếu ký thất bại\"}, {\"id\": 91, \"uuid\": \"b58279f2-c9d3-4324-9904-3e4cb5c392b3\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Quản lý lưu trữ HSBA\", \"display_order\": 9, \"detail_description\": \"Chức năng cho phép người dùng quản lý lưu trữ HSBệnh án. Chức năng Bệnh án gồm các tính năng chính sau:\\n- Hiển thị, tìm kiếm HSBệnh án trên lưới\\n- Cấp số lưu trữ\\n- Phân loại HSBệnh án\\n- Cập nhật vị trí lưu trữ\\n- Xuất danh sách lưu trữ HSBệnh án\"}, {\"id\": 92, \"uuid\": \"ab5563a7-4a97-4102-9182-d8316eaa3301\", \"status\": \"ACTIVE\", \"group_id\": 5, \"created_at\": \"2026-04-02 06:35:10\", \"created_by\": 9, \"product_id\": 27, \"updated_at\": \"2026-04-02 06:35:10\", \"updated_by\": 9, \"feature_name\": \"Quản lý thông tin mượn trả HSBA\", \"display_order\": 10, \"detail_description\": \"Chức năng cho phép người dùng quản lý 