INSERT INTO `audit_logs` VALUES (1027,'d4c23684-1e35-43d7-9da1-bf37652479e0','UPDATE','product_feature_catalogs',64,'{\"groups\": [{\"id\": 35, \"uuid\": \"43afca1c-8a4c-4465-9692-fcc90af1aa26\", \"notes\": null, \"features\": [{\"id\": 152, \"uuid\": \"7e36b0ea-ce5d-4172-b196-cf6e45e6b904\", \"status\": \"ACTIVE\", \"group_id\": 35, \"created_at\": \"2026-04-06 13:59:19\", \"created_by\": 9, \"product_id\": 64, \"updated_at\": \"2026-04-06 13:59:19\", \"updated_by\": 9, \"feature_name\": \"Tích hợp với Hệ thống thông tin xét nghiệm (LIS)\", \"display_order\": 1, \"detail_description\": \"- Chức năng cho phép người dùng tích hợp và gửi thông tin chỉ định thông tin xét nghiệm của bệnh nhân qua hệ thống xét nghiệm\\n- Chức năng cho phép hệ thống thông tin xét nghiệm thực hiện và trả kết quả xét nghiệm của bệnh nhân về hệ thống HIS\"}, {\"id\": 153, \"uuid\": \"ae0c4bc2-bf8c-4746-bebb-448d94eaeb54\", \"status\": \"ACTIVE\", \"group_id\": 35, \"created_at\": \"2026-04-06 13:59:19\", \"created_by\": 9, \"product_id\": 64, \"updated_at\": \"2026-04-06 13:59:19\", \"updated_by\": 9, \"feature_name\": \"Tích hợp với Hệ thống thông tin RIS/PACS\", \"display_order\": 2, \"detail_description\": \"- Chức năng cho phép người dùng tích hợp và gửi thông tin chỉ định CĐHA của bệnh nhân qua hệ thống thông tin RIS/PACS\\n- Chức năng cho phép hệ thống thông tin RIS/PACS thực hiện và trả kết quả hình ảnh của bệnh nhân về hệ thống HIS\"}, {\"id\": 154, \"uuid\": \"f640106d-894b-4c04-896d-e25fec7fedd7\", \"status\": \"ACTIVE\", \"group_id\": 35, \"created_at\": \"2026-04-06 13:59:19\", \"created_by\": 9, \"product_id\": 64, \"updated_at\": \"2026-04-06 13:59:19\", \"updated_by\": 9, \"feature_name\": \"Tích hợp hệ thống hóa đơn điện tử đang sử dụng\", \"display_order\": 3, \"detail_description\": \"- Chức năng cho phép người dùng tích hợp và gửi thông tin hoá đơn điện tử của bệnh nhân đã thanh toán qua hệ thống quản lý danh sách hoá đơn đã phát hành\\n- Chức năng cho phép người dùng thực