  CONSTRAINT `fk_customer_request_status_ref_tasks_created_by` FOREIGN KEY (`created_by`) REFERENCES `internal_users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_customer_request_status_ref_tasks_instance` FOREIGN KEY (`status_instance_id`) REFERENCES `customer_request_status_instances` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_customer_request_status_ref_tasks_ref_task_id` FOREIGN KEY (`ref_task_id`) REFERENCES `request_ref_tasks` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_customer_request_status_ref_tasks_updated_by` FOREIGN KEY (`updated_by`) REFERENCES `internal_users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Liên kết task tham chiếu theo từng trạng thái yêu cầu';
