--
-- Table structure for table `department_weekly_schedule_entries`
--

DROP TABLE IF EXISTS `department_weekly_schedule_entries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `department_weekly_schedule_entries` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `schedule_id` bigint unsigned NOT NULL,
  `calendar_date` date NOT NULL,
  `session` enum('MORNING','AFTERNOON') NOT NULL,
  `sort_order` smallint unsigned NOT NULL DEFAULT '10',
  `work_content` text NOT NULL,
  `location` varchar(255) DEFAULT NULL,
  `participant_text` text,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_dept_week_schedule_entry_group` (`schedule_id`,`calendar_date`,`session`),
  KEY `idx_dept_week_schedule_entry_date` (`calendar_date`),
  CONSTRAINT `fk_dept_week_schedule_entry_calendar` FOREIGN KEY (`calendar_date`) REFERENCES `monthly_calendars` (`date`) ON DELETE RESTRICT,
  CONSTRAINT `fk_dept_week_schedule_entry_schedule` FOREIGN KEY (`schedule_id`) REFERENCES `department_weekly_schedules` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
