DROP TABLE IF EXISTS `tags`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tags` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'ID tag',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tên tag (duy nhất)',
  `color` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT 'blue' COMMENT 'Mã màu: blue, red, green, yellow, purple, pink, orange, teal, gray',
  `description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Mô tả tag',
  `usage_count` int unsigned DEFAULT '0' COMMENT 'Số lần tag được sử dụng',
  `created_by` bigint unsigned DEFAULT NULL COMMENT 'Người tạo tag',
  `updated_by` bigint unsigned DEFAULT NULL COMMENT 'Người cập nhật tag',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Created timestamp',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Updated timestamp',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT 'Soft delete',
  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`),
  KEY `idx_tags_name` (`name`),
  KEY `idx_tags_color` (`color`),
  KEY `idx_tags_usage` (`usage_count`),
  KEY `fk_tags_created_by` (`created_by`),
  KEY `fk_tags_updated_by` (`updated_by`),
  CONSTRAINT `fk_tags_created_by` FOREIGN KEY (`created_by`) REFERENCES `internal_users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_tags_updated_by` FOREIGN KEY (`updated_by`) REFERENCES `internal_users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Danh mục tag cho yêu cầu khách hàng';
